-- Seed representative Analytics workspace fixture data for local SQLite dashboard QA.
--
-- Usage:
--   sqlite3 conductor.db < scripts/seed-analytics-fixtures.sql
--
-- The script is idempotent for the fixed fixture IDs below. It creates one tenant,
-- two users, two credentials, one endpoint, one VMR, six request-history rows, and
-- representative request analytics events for stage and slow-request panels.

PRAGMA foreign_keys=ON;

